#include <stdio.h>
#include <inttypes.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N, K; scanf("%lld %lld", &N, &K);
        long long half = N/2; // floor(N/2)
        long long ans;
        if(K >= half){
            ans = N*(N-1)/2;
        }else{
            ans = K * (2*N - 2*K - 1);
        }
        printf("%lld\n", ans);
    }
    return 0;
}

